parameters.jsCode:
// Extract the first 2-digit CPV code from the model's reply.
const content = $json.choices?.[0]?.message?.content ?? '';
const m = String(content).match(/\b(\d{2})\b/);
return [{ json: { cpv: m ? m[1] : '45' } }];
